import React, { useEffect, useState } from "react";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  BarElement,
  CategoryScale,
  LinearScale,
  Tooltip,
  Legend
} from "chart.js";
import { motion } from "framer-motion";

ChartJS.register(BarElement, CategoryScale, LinearScale, Tooltip, Legend);

export default function App() {
  const [servers, setServers] = useState([]);
  const [search, setSearch] = useState("");
  const [form, setForm] = useState({ name: "", cost: "", cpu: "" });
  const [showForm, setShowForm] = useState(false);

  // ✅ Dummy Data (no backend needed)
  const fetchData = () => {
    const dummy = [
      { _id: "1", name: "AWS-1", cost: 12000, cpu: 75 },
      { _id: "2", name: "Azure-DB", cost: 9000, cpu: 45 },
      { _id: "3", name: "GCP-VM", cost: 15000, cpu: 85 },
      { _id: "4", name: "Storage-X", cost: 6000, cpu: 25 }
    ];
    setServers(dummy);
  };

  useEffect(() => {
    fetchData();
  }, []);

  // CPU auto fluctuation
  useEffect(() => {
    const interval = setInterval(() => {
      setServers(prev =>
        prev.map(s => ({
          ...s,
          cpu: Math.max(5, Math.min(100, s.cpu + (Math.random() * 20 - 10)))
        }))
      );
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const processed = servers.map(s => {
    const savings = Math.round(s.cost * (1 - s.cpu / 100));

    let status = "🟢 Efficient";
    if (s.cpu > 80) status = "🔴 High CPU";
    else if (s.cpu >= 30) status = "🟡 Medium CPU";

    return { ...s, savings, status };
  });

  const filtered = processed.filter(s =>
    s.name.toLowerCase().includes(search.toLowerCase())
  );

  const totalCost = processed.reduce((a, b) => a + b.cost, 0);
  const totalSavings = processed.reduce((a, b) => a + b.savings, 0);

  const addServer = () => {
    const newServer = {
      _id: Date.now().toString(),
      name: form.name,
      cost: Number(form.cost),
      cpu: Number(form.cpu)
    };
    setServers(prev => [...prev, newServer]);
    setShowForm(false);
  };

  const deleteServer = (id) => {
    setServers(prev => prev.filter(s => s._id !== id));
  };

  const chartData = {
    labels: filtered.map(s => s.name),
    datasets: [
      {
        label: "Cost",
        data: filtered.map(s => s.cost),
        backgroundColor: "#ef4444",
        borderRadius: 6
      },
      {
        label: "Savings",
        data: filtered.map(s => s.savings),
        backgroundColor: "#22c55e",
        borderRadius: 6
      }
    ]
  };

  return (
    <div style={styles.app}>
      <div style={styles.sidebar}>
        <h2>📊 Insights</h2>
        <Insight label="📦 Servers" value={processed.length} />
        <Insight label="💰 Cost" value={`₹${totalCost}`} />
        <Insight label="💸 Savings" value={`₹${totalSavings}`} />
      </div>

      <div style={styles.main}>
        <h1 style={styles.heading}>☁️ Cloud Optimization</h1>

        <div style={styles.topbar}>
          <button style={styles.addBtn} onClick={() => setShowForm(true)}>
            ➕ Add Server
          </button>

          <input
            style={styles.search}
            placeholder="Search..."
            onChange={(e) => setSearch(e.target.value)}
          />

          <div style={styles.savings}>💰 ₹{totalSavings}</div>
        </div>

        {showForm && (
          <div style={styles.modal}>
            <div style={styles.modalBox}>
              <input placeholder="Name" onChange={e => setForm({ ...form, name: e.target.value })} />
              <input placeholder="Cost" onChange={e => setForm({ ...form, cost: e.target.value })} />
              <input placeholder="CPU" onChange={e => setForm({ ...form, cpu: e.target.value })} />
              <button onClick={addServer}>Save</button>
              <button onClick={() => setShowForm(false)}>Cancel</button>
            </div>
          </div>
        )}

        <div style={styles.card}>
          <Bar data={chartData} />
        </div>

        <div style={styles.grid}>
          {filtered.map(s => (
            <motion.div
              key={s._id}
              style={styles.cardBox}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              whileHover={{ scale: 1.05 }}
            >
              <h3>{s.name}</h3>
              <p>💰 ₹{s.cost}</p>
              <p>💸 ₹{s.savings}</p>
              <p>⚡ {s.cpu.toFixed(1)}%</p>
              <p>{s.status}</p>

              <button style={styles.deleteBtn} onClick={() => deleteServer(s._id)}>
                Delete
              </button>
            </motion.div>
          ))}
        </div>
      </div>
    </div>
  );
}

const Insight = ({ label, value }) => (
  <div style={styles.insightBox}>
    {label}<br />
    <b>{value}</b>
  </div>
);

const styles = {
  app: { display: "flex", minHeight: "100vh", background: "#f8fafc" },
  sidebar: { width: "260px", padding: "20px", background: "#111827", color: "white" },
  main: { flex: 1, padding: "20px" },
  heading: { textAlign: "center", marginBottom: "15px" },
  topbar: { display: "flex", gap: "12px", marginBottom: "20px" },
  search: { flex: 1, padding: "8px" },
  addBtn: { background: "#3b82f6", color: "white", padding: "10px", border: "none" },
  savings: { background: "#22c55e", padding: "10px", color: "white", marginLeft: "auto" },
  card: { background: "white", padding: "20px", marginBottom: "20px" },
  grid: { display: "flex", gap: "20px", flexWrap: "wrap" },
  cardBox: { background: "#ffffff", padding: "16px", width: "220px", borderRadius: "12px" },
  deleteBtn: { marginTop: "10px", background: "#ef4444", color: "white", border: "none", padding: "8px" },
  modal: { position: "fixed", top: 0, left: 0, width: "100%", height: "100%", background: "rgba(0,0,0,0.6)", display: "flex", justifyContent: "center", alignItems: "center" },
  modalBox: { background: "#fff", padding: "20px" },
  insightBox: { background: "rgba(255,255,255,0.05)", padding: "12px", borderRadius: "10px", marginBottom: "10px" }
};